head.b:skin:
*{box-sizing:border-box;margin:0;padding:0}
body{background:#0d1117;color:#e6edf3;font:16px/1.6 'Inter',system-ui,sans-serif}
a{color:#22d3ee;text-decoration:none}
a:hover{text-decoration:underline}
img{max-width:100%;height:auto}
h1,h2,h3{color:#e6edf3;font-weight:800;line-height:1.3}

.ti-header{background:#0b2038;border-bottom:2px solid #22d3ee;position:sticky;top:0;z-index:50;padding:12px 0}
.ti-header .ti-wrap{display:flex;align-items:center;justify-content:space-between;max-width:1200px;margin:0 auto;padding:0 20px}
.ti-brand{display:flex;align-items:center;gap:12px}
.ti-logo{height:50px;border-radius:6px}
.ti-brand-name{font-size:20px;font-weight:800;color:#e6edf3}
.ti-social{display:flex;gap:10px}
.ti-social a{display:flex;align-items:center;justify-content:center;width:36px;height:36px;border-radius:8px;background:#161b22;border:1px solid #30363d;color:#8b949e;transition:all .15s ease}
.ti-social a:hover{background:#22d3ee;border-color:#22d3ee;color:#0d1117}
.ti-social svg{width:18px;height:18px;fill:currentColor}

.ti-search{display:flex;align-items:center;background:#161b22;border:1px solid #30363d;border-radius:8px;padding:0 12px;height:36px;gap:8px}
.ti-search input{background:none;border:none;color:#e6edf3;font-size:14px;width:180px;outline:none}
.ti-search input::placeholder{color:#8b949e}
.ti-search-icon{color:#8b949e;flex-shrink:0}
.ti-search-icon svg{width:16px;height:16px;fill:currentColor}

.ti-main{max-width:1200px;margin:0 auto;padding:30px 20px}
.ti-grid{display:grid;grid-template-columns:1fr 300px;gap:30px}
@media(max-width:900px){.ti-grid{grid-template-columns:1fr}}

.ti-post{background:#161b22;border:1px solid #30363d;border-radius:12px;padding:24px;margin-bottom:20px}
.ti-post-title{font-size:22px;margin-bottom:10px}
.ti-post-title a{color:#e6edf3}
.ti-post-title a:hover{color:#22d3ee}
.ti-post-meta{color:#8b949e;font-size:13px;margin-bottom:12px}
.ti-post-flex{display:flex;gap:16px;align-items:flex-start}
@media(max-width:560px){.ti-post-flex{flex-direction:column}}
.ti-post-thumb{width:140px;height:90px;object-fit:cover;border-radius:8px;flex-shrink:0}
.ti-post-snippet{color:#b1b8c0;font-size:14px}
.ti-readmore{display:inline-block;margin-top:8px;font-weight:600;font-size:14px;color:#22d3ee}
.ti-post-label{display:inline-block;font-size:11px;color:#22d3ee;background:rgba(34,211,238,0.1);padding:2px 8px;border-radius:4px;margin-bottom:6px}

.ti-pager{display:flex;justify-content:space-between;padding:20px 0}
.ti-pager a{padding:10px 20px;border:1px solid #30363d;border-radius:8px;font-weight:600;background:#161b22;color:#22d3ee}

.sidebar .widget{background:#161b22;border:1px solid #30363d;border-radius:12px;padding:20px;margin-bottom:20px}
.sidebar .widget h2{font-size:12px;text-transform:uppercase;letter-spacing:0.1em;color:#8b949e;margin-bottom:12px;padding-bottom:8px;border-bottom:1px solid #30363d}
.sidebar .widget ul{list-style:none}
.sidebar .widget li{padding:8px 0;border-bottom:1px solid #30363d}
.sidebar .widget li:last-child{border:none}
.sidebar .widget a{color:#22d3ee;font-size:14px}

.ti-footer{background:#010409;text-align:center;padding:24px;margin-top:40px;border-top:1px solid #30363d;color:#8b949e;font-size:13px}
.ti-footer a{color:#22d3ee}

.header .description,.Header .description,.descriptionwrapper{display:none!important}
